Let's start by creating the `DiffLine` data class.

```json
{"name": "write_file", "arguments": {"path": "diff.py", "content": """from dataclasses import dataclass

@dataclass
class DiffLine:
    kind: str
    content: str
    old_lineno: int = 0
    new_lineno: int = 0
"""}}
```

Next, let's implement the `compute_lcs` function.

```json
{"name": "write_file", "arguments": {"path": "diff.py", "content": """from typing import List

def compute_lcs(a: str, b: str) -> str:
    m, n = len(a), len(b)
    lcs = [[''] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                lcs[i][j] = lcs[i - 1][j - 1] + a[i - 1]
            else:
                if len(lcs[i - 1][j]) > len(lcs[i][j - 1]):
                    lcs[i][j] = lcs[i - 1][j]
                else:
                    lcs[i][j] = lcs[i][j - 1]

    return lcs[m][n]
"""}}
```

Now, let's implement the `compute_diff` function.

```json
{"name": "write_file", "arguments": {"path": "diff.py", "content": """from typing import List

def compute_diff(old_lines: List[str], new_lines: List[str]) -> List[DiffLine]:
    m, n = len(old_lines), len(new_lines)
    lcs = [[''] * (n + 1) for _ in range(m + 1)]

    # Build the lcs table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if old_lines[i - 1] == new_lines[j - 1]:
                lcs[i][j] = lcs[i - 1][j - 1] + a[i - 1]
            else:
                if len(lcs[i - 1][j]) > len(lcs[i][j - 1]):
                    lcs[i][j] = lcs[i - 1][j]
                else:
                    lcs[i][j] = lcs[i][j - 1]

    # Backtrack to find the diffs
    i, j = m, n
    diff_lines = []
    while i > 0 or j > 0:
        if i > 0 and j > 0 and old_lines[i - 1] == new_lines[j - 1]:
            diff_lines.append(DiffLine(' ', old_lines[i - 1], i - 1, j - 1))
            i -= 1
            j -= 1
        elif i > 0 and (j == 0 or lcs[i - 1][j] >= lcs[i][j - 1]):
            diff_lines.append(DiffLine('-', old_lines[i - 1], i - 1, 0))
            i -= 1
        else:
            diff_lines.append(DiffLine('+', new_lines[j - 1], 0, j - 1))
            j -= 1

    return diff_lines[::-1]
"""}}
```

